-- 法律修法歷程 batch 2: 性平教育法 / 自殺防治法 / 集會遊行法
-- 由 parallel-research agent 蒐集（2026-04-30）

INSERT OR REPLACE INTO law (law_id, law_name_zh, law_name_en, law_pcode, enacted_date, primary_agency, covers_articles, related_pi, is_implementation_act, note) VALUES
('L004','性別平等教育法','Gender Equity Education Act','H0080067','2004-06-23','教育部','["ICCPR-26","ICCPR-18-4","ICESCR-13","ICESCR-13-3"]','["PI-10","PI-13","PI-16"]',0,'2004 制定全文 38 條；歷經 2010、2011、2013、2018、2022、2023 共 6 次修正；2023-08-16 修正全文 48 條，部分條文 2024-03-08 施行。'),
('L005','自殺防治法','Suicide Prevention Act','L0020213','2019-06-19','衛生福利部','["ICESCR-12"]','["PI-10","PI-13"]',0,'2019-06-19 制定公布全文 19 條，公布日施行；迄今未經修正。確立通報、關懷訪視、媒體限制、罰則四大支柱。'),
('L006','集會遊行法','Assembly and Parade Act','D0080058','1988-01-20','內政部（警政署）','["ICCPR-21","ICCPR-19"]','["PI-13","PI-16"]',0,'1988 制定；1992、2002、2021 共 3 次修正；維持「許可制」迄今 13 年來未廢。釋字 445（1998）、釋字 718（2014）兩度宣告部分條文違憲。');

-- L004 性別平等教育法 7 個版本
INSERT OR REPLACE INTO law_version (version_id, law_id, version_label, promulgated_date, effective_date, full_text_url, legislative_reason, is_current, note) VALUES
('L004-V01','L004','制定','2004-06-23','2004-06-23','https://law.moj.gov.tw/LawClass/LawHistory.aspx?pcode=H0080067','回應 1988 年起婦運推動「兩性平等教育法草案」；2000 年葉永鋕事件後加速立法；確立校園性侵害/性騷擾調查機制、性平委員會、課程綱要納入性別議題。',0,'制定全文 38 條'),
('L004-V02','L004','第一次修正','2010-05-26',NULL,NULL,'配合行政院組改修正第 34、36 條主管機關文字',0,'技術性修正'),
('L004-V03','L004','第二次修正','2011-06-22',NULL,NULL,'回應 2010 年數起校園霸凌與性別事件，強化通報、調查、避免再侵害',0,'修正第 2、12-14、20-28、30、36、38 條'),
('L004-V04','L004','第三次修正','2013-12-11',NULL,NULL,'修正第 25 條：強化加害人懲處之通知與追蹤機制',0,NULL),
('L004-V05','L004','第四次修正','2018-12-28',NULL,NULL,'回應 #MeToo 前哨之師對生事件，增訂第 27-1 條',0,'修正 7 條、增訂 1 條'),
('L004-V06','L004','第五次修正','2022-01-19',NULL,NULL,'配合教師法、教育人員任用條例修正第 27-1、30 條',0,NULL),
('L004-V07','L004','第六次修正（重大）','2023-08-16','2024-03-08','https://law.moj.gov.tw/LawClass/LawHistory.aspx?pcode=H0080067','起因為 2023 #MeToo 風暴。將「校園性侵害/性騷擾/性霸凌」改稱「校園性別事件」；行為人為校長/教職員工時調查小組「全部外聘」；軍警/少年矯正學校納入。',1,'修正全文 48 條（原 38 條）；部分自 2024-03-08 施行');

-- L005 自殺防治法（迄未修正）
INSERT OR REPLACE INTO law_version (version_id, law_id, version_label, promulgated_date, effective_date, full_text_url, legislative_reason, is_current, note) VALUES
('L005-V01','L005','制定','2019-06-19','2019-06-19','https://law.moj.gov.tw/LawClass/LawAll.aspx?pcode=L0020213','回應台灣自 1997 起連 13 年自殺列十大死因之公衛危機，建構國家層級防治體系：跨部會委員會、24 小時諮詢專線、通報關懷網、媒體報導規範。對應 ICESCR Art.12 健康權。',1,'制定全文 19 條；尚未修正');

-- L006 集會遊行法 4 個版本
INSERT OR REPLACE INTO law_version (version_id, law_id, version_label, promulgated_date, effective_date, full_text_url, legislative_reason, is_current, note) VALUES
('L006-V01','L006','制定','1988-01-20','1988-01-20',NULL,'戒嚴解除（1987-07）後立法；保留事前許可制、命令解散、刑罰等威權色彩條款',0,'制定全文 35 條'),
('L006-V02','L006','第一次修正（更名）','1992-07-27',NULL,NULL,'動員戡亂時期終止後配套修正；刪除「主張共產主義或分裂國土」之原條文部分文字、更名為《集會遊行法》',0,'修正第 1、4、9、18、22、27、28、30、31 條'),
('L006-V03','L006','第二次修正','2002-06-26',NULL,NULL,'回應釋字 445（1998）部分意旨，刪除/修正第 11 條原違憲款項；微調申請程序',0,'回應僅完成「違憲款項刪除」，未動「許可制」核心架構'),
('L006-V04','L006','第三次修正','2021-01-27',NULL,NULL,'配合民法成年年齡下修為 18 歲之全面性技術性修正',1,'修正第 10 條；非實質改革');

-- law_article_change 條文 delta
INSERT INTO law_article_change (version_id, article_number, change_type, text_before, text_after, reason, related_co, related_article, note) VALUES
('L004-V07','第 3 條','amended','本法用詞定義如下：……五、校園性侵害、性騷擾或性霸凌事件：……','本法用詞定義如下：……七、校園性別事件：指性侵害、性騷擾、性霸凌事件，或校長、教職員工違反與性或性別有關之專業倫理行為。','概念擴張：將「校園性別事件」定義從三類擴增為四類，新增「違反專業倫理」類型，回應師對生不對等權勢關係案件','[]','["ICCPR-26"]','重大概念變動'),
('L004-V07','第 21 條','amended','學校校長、教師、職員或工友知悉服務學校發生疑似校園性侵害、性騷擾或性霸凌事件者……至遲不得超過二十四小時。','學校校長、教師、職員或工友於執行職務時，知悉服務學校發生疑似校園性別事件者……至遲不得超過二十四小時。','明確化「於執行職務時」之要件；通報用語統一為「校園性別事件」','["CO-3-§47"]','["ICCPR-26"]',NULL),
('L004-V07','第 27-1 條','amended','學校教師有下列各款情形之一者，不得聘任為教師……','擴大解聘/終局不續聘之範圍，納入「違反性或性別專業倫理」之教職員工；於行為人為校長/教職員工時，調查小組成員應全部外聘。','回應 2023 #MeToo 風暴；解決校內人情壓力導致調查不公之沉痾','[]','["ICCPR-26","ICCPR-2-3"]','關鍵改革'),
('L004-V07','第 32 條','amended',NULL,'學校或主管機關處理校園性別事件，應告知被害人、行為人或其實際照顧者本法所定權益及救濟途徑；必要時並應提供法律協助、心理諮商輔導及社會福利資源轉介服務。','增訂「實際照顧者」之程序保障；強化父母/監護人之知情與救濟權，部分回應家長團體訴求','[]','["ICCPR-18-4"]','此為國教盟長期倡議之程序透明化條款，但**未引入家長 opt-out 課程選擇權**'),

('L005-V01','第 11 條','new',NULL,'醫事人員、社工人員、長期照顧服務人員、學校人員、警察人員、消防人員、矯正機關人員或其他相關業務人員，於執行業務時知悉有自殺行為情事者，應通報直轄市、縣（市）主管機關。','建立八大職類強制通報義務','[]','["ICESCR-12"]','關鍵條文'),
('L005-V01','第 16 條','new',NULL,'宣傳品、出版品、廣播、電視、網際網路或其他媒體，不得報導或記載下列事項：一、教導自殺方法或教唆、誘使、煽惑民眾自殺之訊息。二、詳細描述自殺個案之自殺方法及原因。三、誘導自殺之文字、聲音、圖片或影像資料。四、毒性物質或其他致命性自殺工具之銷售情報。五、其他經中央主管機關認定足以助長自殺之情形。','對應 WHO 媒體報導指引；防範 Werther 效應','[]','["ICESCR-12","ICCPR-19-3"]','言論自由與健康權之衡平'),
('L005-V01','第 18 條','new',NULL,'廣播、電視事業違反第十六條規定者，由目的事業主管機關處新臺幣十萬元以上一百萬元以下罰鍰，並令其限期改正。','媒體違反報導規範之罰則','[]','["ICCPR-19-3"]',NULL),

('L006-V03','第 11 條','amended','申請室外集會、遊行，除有左列情事之一者外，應予許可：一、違反第四條（主張共產主義或分裂國土）……二、有事實足認為有危害國家安全、社會秩序或公共利益之虞者。三、有危害生命、身體、自由或對財物造成重大損壞之虞者。','刪除釋字 445 認定違憲之第二、三款（事實足認虞之事前審查），保留第一款（違反第 4 條）及其餘款。','僅做違憲款項之最小修正；許可制本身未動','[]','["ICCPR-21"]','改革不徹底；釋字 718 又於 2014 再次宣告緊急/偶發性集會適用許可制違憲');

-- law_amendment 修法事件
INSERT OR REPLACE INTO law_amendment (amendment_id, law_id, version_id, related_event_id, proposal_date, third_reading, promulgated, proposer_summary, contention_level, summary_before, summary_after, key_changes, related_executive_orders, triggered_by_co, note) VALUES
('AMD-2023-002','L004','L004-V07',NULL,'2023-07-13','2023-07-28','2023-08-16','行政院提案＋跨黨派立委併案；2023 #MeToo 風暴下朝野共識通過','high','校園性別事件三類型；師生不對等權勢無獨立類型；調查小組校內外混合；軍警校未納入','擴張為四類型（含違反專業倫理）；行為人為校長/教職員時調查小組全部外聘；軍警/少矯正校納入；實習督導視為教師；強化實際照顧者告知義務','["四類型化","全部外聘調查","軍警納入","實習督導入法","實際照顧者告知"]','["EO-2024-001","EO-2024-002"]','["CO-3-§47"]','**家長 opt-out 課程選擇權條款於本次修法亦未納入**；國教盟與部分家長團體於審議期間提案之「課程實施前家長知情同意」未獲採納'),
('AMD-2002-006','L006','L006-V03',NULL,NULL,NULL,'2002-06-26','跨黨派；以行政院版為基礎','medium','許可制＋第 11 條三款違憲申請駁回事由（含主張共產主義/分裂國土、虞之審查）','刪除釋字 445 違憲之兩款；保留許可制核心','["違憲款項刪除","許可制保留"]','[]','[]','釋字 445（1998）之最小回應；未滿足公約意旨'),
('AMD-NULL-2017','L006',NULL,NULL,'2016-2017',NULL,NULL,'執政黨團與時代力量黨團多版本；國民黨團未提案','very_high','許可制；命令解散；刑罰；禁制區','報備制；行政罰金為主；保障型法制','["許可制改報備制","刪除刑罰","禁制區檢討","更名為集會遊行保障法"]','[]','["CO-1","CO-2"]','**完全執政期間（2016-2024）之修法卡關**：行政院版未送出、立委版止於委員會。原因：警政體系反對、執政黨憂慮街頭運動反噬、缺政治意願'),
('AMD-NULL-2024','L006',NULL,NULL,'2024-',NULL,NULL,'行政院 2024 預告草案：緊急/偶發性集會改報備制（部分回應釋字 718）','high','許可制全面適用','一般集會仍許可制；緊急/偶發性改報備制（混合制）','["緊急偶發改報備","一般仍許可","刑罰存廢未定"]','[]','["CO-3"]','3rd CO（2022）再度要求廢除許可制；行政院 2024-06 再啟修法但僅做釋字 718 之最低限度回應');

